import { useState } from 'react';
import { Button, OverlayTrigger, Popover } from 'react-bootstrap';

const emojis = [
  '😂',
  '🤣',
  '😅',
  '🥲',
  '😑',
  '🫠',
  '😭',
  '🤡',
  '💀',
  '💩',
  '🫵',
  '🤦‍♂️',
  '🤷‍♂️',
];
const emojiPlaceHolder = (
  <svg
    width="26"
    height="26"
    fill="none"
    viewBox="0 0 24 24"
    role="img"
    aria-label="Emoji-icon"
    data-testid="emojiIconButton"
    color="#5E6C84"
    size="26"
  >
    <path
      fill="#5E6C84"
      fill-rule="evenodd"
      d="M12 2.75a9.25 9.25 0 1 0 0 18.5 9.25 9.25 0 0 0 0-18.5M1.25 12C1.25 6.063 6.063 1.25 12 1.25S22.75 6.063 22.75 12 17.937 22.75 12 22.75 1.25 17.937 1.25 12m6.363 2.51a.75.75 0 0 1 1.052.13c.85 1.089 1.916 1.607 3.336 1.607s2.485-.518 3.335-1.607a.75.75 0 1 1 1.182.923c-1.14 1.46-2.644 2.184-4.517 2.184-1.873 0-3.378-.724-4.518-2.184a.75.75 0 0 1 .13-1.053"
      clip-rule="evenodd"
    ></path>
    <path
      fill="#5E6C84"
      d="M10.332 9.914a1.25 1.25 0 1 1-2.5 0 1.25 1.25 0 0 1 2.5 0M16.164 9.914a1.25 1.25 0 1 1-2.5 0 1.25 1.25 0 0 1 2.5 0"
    ></path>
  </svg>
);
export default function EmojiPickerButton({
  showEmojiPopOver,
  setShowEmojiPopOver,
  onSelect,
  container = undefined,
}) {
  const handleEmojiClick = (emoji) => {
    onSelect(emoji);
    // setShow(false);
  };

  const popover = (
    <Popover id="emoji-popover">
      <Popover.Body>
        <div
          style={{
            display: 'flex',
            flexWrap: 'wrap',
            gap: '8px',
            maxWidth: '200px',
          }}
        >
          {emojis.map((emoji, i) => (
            <span
              key={i}
              style={{ fontSize: '22px', cursor: 'pointer' }}
              onClick={() => handleEmojiClick(emoji)}
            >
              {emoji}
            </span>
          ))}
        </div>
      </Popover.Body>
    </Popover>
  );

  return (
    <OverlayTrigger
      container={container}
      trigger="click"
      placement="bottom"
      show={showEmojiPopOver}
      overlay={popover}
      rootClose
      onHide={() => setShowEmojiPopOver(false)}
    >
      <Button
        size="sm"
        variant="dark"
        onClick={() => {
          setShowEmojiPopOver((prev) => !prev);
          console.log(container);
        }}
      >
        {emojiPlaceHolder}
      </Button>
    </OverlayTrigger>
  );
}
