import React, { useRef, useEffect } from 'react';
import { useState } from 'react';
import { Button } from 'react-bootstrap';
import EmojiPickerButton from './EmojiPickerButton';

export default function Chat({
  messages,
  msgInput,
  setMsgInputFocused,
  sendMsg,
  setMsgInput,
}) {
  const chatListRef = useRef(null);
  const [showEmojiPopOver, setShowEmojiPopOver] = useState(false);
  useEffect(() => {
    if (chatListRef.current) {
      chatListRef.current.scrollTop = chatListRef.current.scrollHeight;
    }
  }, [messages]);

  return (
    <div className="chats">
      <h2>چت</h2>
      <hr style={{ marginBottom: '1rem' }} />
      <ul ref={chatListRef}>
        {messages.map((msgObj, idx) => {
          return (
            <li className="messeage-text" key={idx}>
              {msgObj.name}:{msgObj.text}
            </li>
          );
        })}
      </ul>
      <div style={{ marginTop: 'auto' }}>
        <input
          id="msg-input"
          value={msgInput}
          placeholder="چت کنید"
          onClick={(e) => {
            setMsgInputFocused(true);
          }}
          onKeyDown={(e) => {
            const { code } = e;
            console.log(code);
            if (code === 'Enter' || code === 'NumpadEnter') sendMsg();
          }}
          onChange={(e) => {
            setMsgInput(e.target.value);
          }}
          type="text"
          className="form-control"
        />
        <EmojiPickerButton
          showEmojiPopOver={showEmojiPopOver}
          setShowEmojiPopOver={setShowEmojiPopOver}
          container={undefined}
          onSelect={(emoji) => {
            setMsgInput(msgInput + emoji);
          }}
        />
        <Button
          style={{ marginTop: '0.5rem' }}
          onClick={() => {
            sendMsg();
            setShowEmojiPopOver(false);
          }}
        >
          ارسال
        </Button>
      </div>
    </div>
  );
}
