import React from 'react';
import { useEffect } from 'react';
import { useState } from 'react';
import { Button, Col, Row } from 'react-bootstrap';
import { useNavigate } from 'react-router-dom';
import { useSocket } from '../context/socket';
import jwtDecode from 'jwt-decode';

export default function Room() {
  const nav = useNavigate();
  const [name, setName] = useState('');

  const { socket, connectSocket } = useSocket();
  useEffect(() => {
    async function run() {
      setName(localStorage.getItem('name') || '');
      if (socket.disconnected) await connectSocket();
    }
    run();
  }, []);

  return (
    <div id="room-page">
      <h2 className="mb-5"> ساخت اتاق جدید </h2>
      <div dir="rtl" className="row input-name-wrapper">
        <div className="col">
          <label style={{ alignSelf: 'flex-end' }} htmlFor="userName">
            نام كاربري(فارسي)
          </label>
          <input
            id="userName"
            value={name}
            onChange={(e) => setName(e.target.value)}
            className="form-control w-100 mb-2"
            dir="rtl"
          />
        </div>
        <div className="col">
          <Button
            className=""
            onClick={() => {
              localStorage.setItem('name', name);
              alert('اسمت عوض شد');
            }}
          >
            ذخیره اسم
          </Button>
        </div>
      </div>
      <div className="room-description mt-1 mb-3">
        <ol className="room-warnings ">
          <li>-قبل از ورود به اتاق از تنظیم بودن ساعت دستگاهت مطمئن شو</li>
          <br />
          <li>-از آخرین نسخه کروم استفاده کن</li>
          <br />
          <li>-اگه از برنامه ویس کال استفاده میکنی،از دیسکورد استفاده کن</li>
        </ol>
      </div>
      <Button
        onClick={() => {
          socket.emit('createRoom', (id) => {
            window.location = `/room/${id}`;
          });
        }}
        type="submit"
        className="w-100 mt-2"
      >
        ساخت اتاق
      </Button>
    </div>
  );
}
